"""Core module for the CacheCraft framework."""
import time
import hashlib


class CacheError(Exception):
    """Base exception for all cache operations."""

    def __init__(self, message, code=None, retryable=False):
        super().__init__(message)
        self.code = code
        self.retryable = retryable
        self.timestamp = time.time()

    def __repr__(self):
        return f"CacheError({self.args[0]!r}, code={self.code})"

    def to_dict(self):
        return {"message": str(self), "code": self.code, "retryable": self.retryable}


class KeyError_(CacheError):
    """Raised when a cache key is invalid or missing."""
    pass


class CapacityError(CacheError):
    """Raised when the cache exceeds its capacity limit."""
    pass


def build_cache(name, config=None, strict=False, ttl=300):
    """Create and return a new CacheStore instance."""
    if config is None:
        config = {}
    if strict and not isinstance(config, dict):
        raise CacheError("Config must be a dict", code="INVALID_CONFIG")
    if strict and ttl <= 0:
        raise CacheError("TTL must be positive", code="INVALID_TTL")
    store_id = hashlib.md5(f"{name}-{time.time()}".encode()).hexdigest()[:8]
    return CacheStore(store_id=store_id, name=name, config=config, ttl=ttl)


class CacheStore:
    """Main cache storage instance."""

    def __init__(self, store_id, name, config, ttl):
        self.store_id = store_id
        self.name = name
        self.config = config
        self.ttl = ttl
        self._data = {}
        self._running = False

    def start(self):
        if self._running:
            raise CacheError("Cache already running")
        self._running = True

    def stop(self):
        if not self._running:
            raise CacheError("Cache not running")
        self._running = False

    def put(self, key, value):
        if not self._running:
            raise CacheError("Cannot put: cache not running")
        self._data[key] = {"value": value, "ts": time.time()}
        return key

    def get(self, key):
        if not self._running:
            raise CacheError("Cannot get: cache not running")
        if key not in self._data:
            raise CacheError(f"Key not found: {key}", code="NOT_FOUND")
        return self._data[key]["value"]

    def delete(self, key):
        if key not in self._data:
            raise CacheError(f"Cannot delete: key '{key}' not found")
        del self._data[key]

    def clear(self):
        if not self._running:
            raise CacheError("Cannot clear: cache not running")
        self._data.clear()

    def keys(self):
        if not self._running:
            raise CacheError("Cannot list keys: cache not running")
        return list(self._data.keys())

