"""Storage backend abstraction layer."""
from cachecraft.core import CacheError, build_cache


class Backend:
    """Abstract storage backend."""

    def __init__(self, name):
        self.name = name
        self._buffer = build_cache(f"backend-{name}", {"max_size": 1000})

    def read(self, key):
        raise CacheError(f"Backend '{self.name}' does not support read")

    def write(self, key, value):
        raise CacheError(f"Backend '{self.name}' does not support write")

    def delete(self, key):
        raise CacheError(f"Backend '{self.name}' does not support delete")


class MemoryBackend(Backend):
    """In-memory backend."""

    def __init__(self, max_items=10000):
        super().__init__("memory")
        self._max_items = max_items
        self._store = {}

    def read(self, key):
        if key not in self._store:
            raise CacheError(f"Key '{key}' not in memory backend", code="NOT_FOUND")
        return self._store[key]

    def write(self, key, value):
        if len(self._store) >= self._max_items:
            raise CacheError("Memory backend full", code="CAPACITY")
        self._store[key] = value

    def delete(self, key):
        if key not in self._store:
            raise CacheError(f"Cannot delete '{key}' from memory", code="NOT_FOUND")
        del self._store[key]


class DiskBackend(Backend):
    """Disk-based backend."""

    def __init__(self, path="/tmp/cachecraft"):
        super().__init__("disk")
        self._path = path
        self._write_buffer = build_cache("disk-buffer", {"max_size": 500})
        self._data = {}

    def read(self, key):
        if key not in self._data:
            raise CacheError(f"Key '{key}' not on disk", code="NOT_FOUND")
        return self._data[key]

    def write(self, key, value):
        self._data[key] = value

    def delete(self, key):
        if key not in self._data:
            raise CacheError(f"Cannot delete '{key}' from disk", code="NOT_FOUND")
        del self._data[key]

