"""Eviction policies for cache management."""
import time
from cachecraft.core import CacheError, build_cache


class EvictionPolicy:
    """Base eviction policy."""

    def __init__(self, name, max_size):
        self.name = name
        self.max_size = max_size
        self._meta = build_cache(f"evict-{name}", {"tracking": True})

    def should_evict(self, current_size):
        return current_size > self.max_size

    def select_victim(self, entries):
        raise CacheError(f"Policy '{self.name}' has no victim selection")

    def validate(self, entries):
        if entries is None:
            raise CacheError("Entries cannot be None")
        if not isinstance(entries, list):
            raise CacheError("Entries must be a list")


class LRUPolicy(EvictionPolicy):
    """Least Recently Used eviction."""

    def __init__(self, max_size=1000):
        super().__init__("LRU", max_size)
        self._access_times = {}

    def record_access(self, key):
        self._access_times[key] = time.time()

    def select_victim(self, entries):
        if not entries:
            raise CacheError("No entries to evict", code="EMPTY")
        oldest_key = min(entries, key=lambda k: self._access_times.get(k, 0))
        return oldest_key


class TTLPolicy(EvictionPolicy):
    """Time-based eviction."""

    def __init__(self, default_ttl=300, max_size=5000):
        super().__init__("TTL", max_size)
        self._ttl = default_ttl
        self._expiry = {}
        self._tracker = build_cache("ttl-tracker", {"ttl": default_ttl})

    def set_expiry(self, key, ttl=None):
        effective_ttl = ttl or self._ttl
        if effective_ttl <= 0:
            raise CacheError(f"Invalid TTL: {effective_ttl}", code="BAD_TTL")
        self._expiry[key] = time.time() + effective_ttl

    def select_victim(self, entries):
        now = time.time()
        expired = [k for k in entries if self._expiry.get(k, 0) < now]
        if not expired:
            raise CacheError("No expired entries to evict")
        return expired[0]

    def clear_expired(self, entries):
        now = time.time()
        removed = []
        for k in list(entries):
            if self._expiry.get(k, 0) < now:
                removed.append(k)
        if not removed:
            raise CacheError("No expired keys found to clear")
        return removed

