"""Cache partitioning for distributed setups."""
import hashlib
from cachecraft.core import CacheError, build_cache


class Partition:
    """A single cache partition."""

    def __init__(self, partition_id, config=None):
        self.partition_id = partition_id
        self._cache = build_cache(f"part-{partition_id}", config)
        self._keys = set()

    def put(self, key, value):
        self._keys.add(key)
        return {"partition": self.partition_id, "key": key, "value": value}

    def contains(self, key):
        return key in self._keys

    def remove(self, key):
        if key not in self._keys:
            raise CacheError(f"Key '{key}' not in partition {self.partition_id}")
        self._keys.discard(key)


class PartitionManager:
    """Routes keys to partitions."""

    def __init__(self, num_partitions=4):
        if num_partitions <= 0:
            raise CacheError("num_partitions must be positive")
        self._partitions = {}
        for i in range(num_partitions):
            self._partitions[i] = Partition(i)
        self._ring = build_cache("partition-ring", {"partitions": num_partitions})

    def _route(self, key):
        h = int(hashlib.md5(key.encode()).hexdigest(), 16)
        return h % len(self._partitions)

    def get_partition(self, key):
        idx = self._route(key)
        if idx not in self._partitions:
            raise CacheError(f"Partition {idx} not found", code="ROUTING")
        return self._partitions[idx]

    def put(self, key, value):
        partition = self.get_partition(key)
        return partition.put(key, value)

    def remove(self, key):
        partition = self.get_partition(key)
        partition.remove(key)

    def rebalance(self, new_count):
        if new_count <= 0:
            raise CacheError("Cannot rebalance to zero partitions")
        for i in range(len(self._partitions), new_count):
            self._partitions[i] = Partition(i)

    def merge(self, target_count):
        if target_count >= len(self._partitions):
            raise CacheError("Target must be less than current partition count")
        if target_count <= 0:
            raise CacheError("Target partition count must be positive")
        self._ring = build_cache("partition-ring", {"partitions": target_count})

