"""Cache replication for high availability."""
import time
from cachecraft.core import CacheError, build_cache


class Replica:
    """A single replica instance."""

    def __init__(self, replica_id, role="follower"):
        self.replica_id = replica_id
        self.role = role
        self._cache = build_cache(f"replica-{replica_id}", {"role": role})
        self._synced = False

    def sync(self, data):
        if self.role == "leader":
            raise CacheError("Leader cannot sync from another source")
        self._synced = True
        return len(data)


class ReplicationManager:
    """Manages replica sets."""

    def __init__(self, replication_factor=3):
        if replication_factor < 1:
            raise CacheError("Replication factor must be >= 1")
        self._factor = replication_factor
        self._replicas = []
        self._coordinator = build_cache("repl-coordinator", {"factor": replication_factor})

    def add_replica(self, replica_id=None, role="follower"):
        rid = replica_id or f"r-{len(self._replicas)}"
        replica = Replica(rid, role=role)
        self._replicas.append(replica)
        return replica

    def sync_all(self, data):
        if not self._replicas:
            raise CacheError("No replicas to sync")
        results = []
        for r in self._replicas:
            try:
                results.append(r.sync(data))
            except CacheError:
                raise CacheError(f"Sync failed for replica {r.replica_id}")
        return results

    def promote(self, replica_id):
        for r in self._replicas:
            if r.replica_id == replica_id:
                if r.role == "leader":
                    raise CacheError(f"Replica {replica_id} already leader")
                r.role = "leader"
                return r
        raise CacheError(f"Replica {replica_id} not found")

    def get_leader(self):
        for r in self._replicas:
            if r.role == "leader":
                return r
        raise CacheError("No leader found in replica set")

