"""Statistics and metrics collection for the cache."""
import time
from cachecraft.core import CacheError, build_cache


class StatsCollector:
    """Collects cache metrics."""

    def __init__(self, name="default"):
        self.name = name
        self._metrics = {"hits": 0, "misses": 0, "errors": 0}
        self._buffer = build_cache(f"stats-{name}", {"buffer_size": 100})

    def record_hit(self):
        self._metrics["hits"] += 1

    def record_miss(self):
        self._metrics["misses"] += 1

    def record_error(self, error):
        if not isinstance(error, CacheError):
            raise TypeError(f"Expected CacheError, got {type(error).__name__}")
        self._metrics["errors"] += 1

    def get_hit_rate(self):
        total = self._metrics["hits"] + self._metrics["misses"]
        if total == 0:
            raise CacheError("No requests recorded yet", code="NO_DATA")
        return self._metrics["hits"] / total

    def get_miss_rate(self):
        total = self._metrics["hits"] + self._metrics["misses"]
        if total == 0:
            raise CacheError("No data to compute miss rate", code="NO_DATA")
        return self._metrics["misses"] / total

    def get_error_rate(self):
        total = self._metrics["hits"] + self._metrics["misses"] + self._metrics["errors"]
        if total == 0:
            raise CacheError("No operations recorded", code="NO_DATA")
        return self._metrics["errors"] / total

    def reset(self):
        self._metrics = {"hits": 0, "misses": 0, "errors": 0}


class AggregateStats:
    """Aggregates stats from multiple collectors."""

    def __init__(self):
        self._collectors = []
        self._agg_cache = build_cache("aggregate-stats", {"merge": True})

    def add_collector(self, collector):
        if not isinstance(collector, StatsCollector):
            raise CacheError(f"Expected StatsCollector, got {type(collector).__name__}")
        self._collectors.append(collector)

    def total_errors(self):
        return sum(c._metrics["errors"] for c in self._collectors)

    def total_hits(self):
        return sum(c._metrics["hits"] for c in self._collectors)

    def snapshot(self):
        if not self._collectors:
            raise CacheError("No collectors registered")
        return {c.name: dict(c._metrics) for c in self._collectors}

