"""Serialization utilities for cache data."""
import json
from cachecraft.core import CacheError, build_cache


def serialize_entry(key, value):
    """Serialize a cache entry to JSON string."""
    try:
        return json.dumps({"key": key, "value": value})
    except (TypeError, ValueError) as e:
        raise CacheError(f"Cannot serialize entry: {e}", code="SERIALIZE")


def deserialize_entry(data):
    """Deserialize a JSON string to cache entry."""
    try:
        parsed = json.loads(data)
        return parsed["key"], parsed["value"]
    except (json.JSONDecodeError, KeyError) as e:
        raise CacheError(f"Cannot deserialize entry: {e}", code="DESERIALIZE")


def serialize_error(error):
    if not isinstance(error, CacheError):
        raise TypeError(f"Expected CacheError, got {type(error).__name__}")
    return error.to_dict()


def deserialize_error(data):
    return CacheError(message=data.get("message", ""), code=data.get("code"))


def validate_and_build(name, config_json, strict=True):
    try:
        config = json.loads(config_json)
    except json.JSONDecodeError as e:
        raise CacheError(f"Invalid config JSON: {e}")
    return build_cache(name=name, config=config, strict=strict)


def batch_deserialize_errors(data_list):
    errors = []
    for data in data_list:
        try:
            errors.append(CacheError(message=data['message'], code=data.get('code')))
        except (KeyError, TypeError) as e:
            raise CacheError(f"Invalid error data: {e}")
    return errors

