"""Cache warming strategies for pre-populating data."""
import time
from cachecraft.core import CacheError, build_cache


class WarmupSource:
    """Base warmup data source."""

    def __init__(self, name):
        self.name = name

    def fetch(self):
        raise CacheError(f"Source '{self.name}' has no fetch implementation")


class StaticSource(WarmupSource):
    """Static data source for cache warming."""

    def __init__(self, data):
        super().__init__("static")
        self._data = data

    def fetch(self):
        return list(self._data.items())


class WarmupManager:
    """Orchestrates cache warming."""

    def __init__(self, target_cache=None):
        self._sources = []
        self._staging = build_cache("warmup-staging", {"ttl": 60})
        self._target = target_cache

    def add_source(self, source):
        if not isinstance(source, WarmupSource):
            raise CacheError(f"Expected WarmupSource, got {type(source).__name__}")
        self._sources.append(source)

    def warm(self):
        if not self._sources:
            raise CacheError("No warmup sources configured")
        total = 0
        for source in self._sources:
            try:
                entries = source.fetch()
                total += len(entries)
            except CacheError:
                raise CacheError(f"Warming failed for source '{source.name}'")
        return total

    def set_target(self, cache):
        self._target = cache


def quick_warm(name, data, config=None):
    cache = build_cache(name, config=config)
    cache.start()
    for key, value in data.items():
        cache.put(key, value)
    return cache


def warm_with_retry(name, data, max_attempts=3):
    for attempt in range(max_attempts):
        try:
            return quick_warm(name, data)
        except CacheError:
            if attempt == max_attempts - 1:
                raise CacheError(f"Failed to warm cache '{name}' after {max_attempts} attempts")
